    if (currentStatus === 'Đã đậu') return 'bg-emerald-50 text-emerald-600 border-emerald-200';
    if (currentStatus === 'Thi lại') return 'bg-rose-50 text-rose-600 border-rose-200';
    if (currentStatus === 'Nghỉ học') return 'bg-gray-50 text-gray-600 border-gray-200';
    return 'bg-gray-50 text-gray-500 border-gray-200';
