        getCities().catch(() => ({})),
        getCourses(1, 100, { status: 'Sắp khai giảng' }).catch(() => ({})),
        getLicenseCategories().catch(() => ({})),
        getLeads().catch(() => ({})),
      ]).then(([settingsRes, citiesRes, coursesRes, licenseRes, leadsRes]) => {
        if (cancelled) return;
        if (settingsRes?.success) setSettings(settingsRes.data);
        if (citiesRes?.success) setCities(citiesRes.data?.data || citiesRes.data || []);
        if (coursesRes?.success) setCourses(coursesRes.data?.docs || coursesRes.data?.data || coursesRes.data || []);
        if (licenseRes?.success) setLicenseCats(licenseRes.data?.data || licenseRes.data || []);
        if (leadsRes?.success) setLeads(leadsRes.data || []);
      });
    }
    return () => { cancelled = true; };
  }, [isOpen]);

  // Fetch student-specific data (full profile, exams, payments, history)
  useEffect(() => {
    let cancelled = false;
    const fetchData = async () => {
      const studentId = student?.id || (student as any)?._id;
      if (!isOpen || !studentId) return;

      try {
        // Fetch profile
        const profileRes = await getStudentById(studentId);
        if (cancelled) return;
        if (profileRes.success) {
          setFullData(profileRes.data);
        } else {
          setFullData({});
        }

        // Fetch related lists
        const [examRes, paymentRes, historyRes] = await Promise.all([
          getExamsByStudent(studentId).catch(() => ({})),
          getPaymentsByStudent(studentId).catch(() => ({})),
          getStudentHistory(studentId, 1, 50).catch(() => ({})),
        ]);

        if (cancelled) return;
        if (examRes?.success) setExams(examRes.data || []);
        if (paymentRes?.success) setPaymentHistory(paymentRes.data?.data || paymentRes.data || []);
        if (historyRes?.success) setSystemHistory(historyRes.data?.data || historyRes.data || []);
      } catch (error) {
        if (!cancelled) {
          console.error('Lỗi tải thông tin chi tiết học viên:', error);
          setFullData({});
        }
      }
    };

    if (isOpen) {
      fetchData();
    } else {
      setFullData(null);
      setSelectedRank('');
      setSelectedCity('');
      setSelectedCourse('');
      setSelectedDob('');
      setSelectedEnrollmentDate('');
    }
    return () => { cancelled = true; };
  }, [isOpen, student?.id]);

